CREATE TABLE `motif` (
  `id_motif` int(10) UNSIGNED NOT NULL,
  `nama_motif` varchar(120) NOT NULL,
  `label_model` varchar(50) DEFAULT NULL,
  `asal_daerah` varchar(120) NOT NULL,
  `pulau` varchar(60) DEFAULT NULL,
  `provinsi` varchar(100) DEFAULT NULL,
  `sejarah` text DEFAULT NULL,
  `filosofi` text DEFAULT NULL,
