  `tingkat_kelangkaan` varchar(80) DEFAULT 'Umum digunakan',
  `harga_cap_min` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `harga_cap_max` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `harga_tulis_min` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `harga_tulis_max` int(10) UNSIGNED NOT NULL DEFAULT 0,
