INSERT INTO `motif` (`id_motif`, `nama_motif`, `label_model`, `asal_daerah`, `pulau`, `provinsi`, `sejarah`, `filosofi`, `karakteristik`, `makna_warna`, `warna_dominan`, `jenis_batik`, `cara_pembuatan`, `penggunaan`, `acara_cocok`, `tingkat_kelangkaan`, `harga_cap_min`, `harga_cap_max`, `harga_tulis_min`, `harga_tulis_max`, `referensi`, `created_at`) VALUES
(1, 'Batik Barong', 'Bali_Barong', 'Bali', 'Bali', 'Provinsi Bali', 'Motif Barong terinspirasi dari Barong, makhluk mitologis pelindung dalam kepercayaan Hindu Bali yang telah hadir sejak ratusan tahun. Motif ini berkembang pesat seiring tradisi seni batik di Bali yang mendapat pengaruh dari Jawa namun beradaptasi dengan estetika Hindu-Bali.', 'Barong melambangkan kebaikan, kekuatan pelindung, dan keseimbangan antara kekuatan baik dan jahat dalam kosmologi Hindu Bali. Pemakainya dipercaya mendapat perlindungan dari energi negatif.', 'Menampilkan wajah Barong (singa mitologis) besar dengan detail ukiran ornamental khas Bali seperti sulur-suluran, bunga, dan elemen dekoratif yang kaya. Komposisi simetris dan penuh detail.', 'Merah melambangkan keberanian dan semangat; emas melambangkan kemewahan dan kesucian; hitam melambangkan kegelapan yang harus dilawan oleh kekuatan Barong.', 'Merah, Emas, Hitam, Coklat', 'Batik Tulis, Batik Cap', 'Dibuat menggunakan teknik batik tulis dengan canting untuk detail halus. Proses pewarnaan menggunakan teknik tutup-celup dengan pewarna sintetis modern maupun alam.', 'Digunakan sebagai busana upacara keagamaan Hindu, pernikahan adat Bali, dan festival budaya. Juga populer sebagai busana fashion dan koleksi seni.', 'Upacara Keagamaan, Pernikahan Adat Bali, Festival Budaya, Fashion', 'Digunakan pada upacara adat tertentu', 250000, 900000, 2500000, 8000000, 'Djelantik, A.A.M. (1990). Balinese Aesthetics. Singapore: Archipelago Press; Tirta, I. (2009). Batik: A Play of Lights and Shadows. Jakarta: PT Gaya Favorit Press.', '2026-07-15 21:04:36'),
(2, 'Batik Ondel-Ondel', 'Jakarta_OndelOndel', 'DKI Jakarta', 'Jawa', 'DKI Jakarta', 'Batik motif Ondel-Ondel lahir sebagai ekspresi identitas budaya Betawi modern, berkembang signifikan sejak tahun 1990-an sebagai upaya pelestarian budaya asli Jakarta di tengah modernisasi kota.', 'Ondel-ondel sebagai boneka raksasa khas Betawi melambangkan pelindung kampung dari roh jahat. Motif ini merayakan kegembiraan, keragaman, dan semangat persatuan warga Jakarta.', 'Menampilkan sosok Ondel-ondel (boneka raksasa berwajah merah untuk laki-laki dan putih untuk perempuan) dalam berbagai komposisi. Sering dilengkapi dengan motif flora khas Betawi seperti kembang kelapa.', 'Merah pada wajah Ondel-ondel jantan melambangkan keberanian; putih pada Ondel-ondel betina melambangkan kelembutan; hijau melambangkan kesuburan dan kehidupan.', 'Merah, Putih, Hijau, Emas, Hitam', 'Batik Tulis, Batik Cap, Batik Printing', 'Proses pembuatan menggunakan teknik batik tulis dan cap. Penggunaan warna cerah dan kontras menjadi ciri khas batik Betawi yang mencerminkan karakter masyarakat Jakarta yang dinamis.', 'Pakaian sehari-hari, busana festival budaya Betawi, souvenir khas Jakarta, busana resmi acara daerah.', 'Festival Budaya Betawi, Acara Resmi Daerah, Sehari-hari, Fashion', 'Umum digunakan', 75000, 300000, 750000, 3000000, 'Shahab, A. (2001). Robinhood Betawi: Si Pitung. Jakarta: Republika; Dinas Pariwisata DKI Jakarta (2019). Warisan Budaya Betawi.', '2026-07-15 21:04:36'),
(3, 'Batik Tumpal', 'Jakarta_Tumpal', 'DKI Jakarta', 'Jawa', 'DKI Jakarta', 'Tumpal adalah motif geometris kuno yang ditemukan pada kain-kain adat Betawi sejak zaman prakolonial. Motif ini merupakan salah satu motif tertua dalam tradisi tekstil Betawi, dengan bukti keberadaan pada kain-kain ceremonial abad ke-18.', 'Tumpal berbentuk segitiga yang berulang melambangkan gunung atau puncak yang merupakan tempat bersemayamnya roh leluhur. Motif ini membawa makna perlindungan dan penghubung antara dunia manusia dengan dunia spiritual.', 'Motif geometris berupa deretan segitiga yang saling berhadapan, membentuk pola zig-zag atau gigi gergaji. Biasanya ditempatkan di tepi kain sebagai border dekoratif yang kuat.', 'Hitam dan putih melambangkan keseimbangan dunia; warna merah sebagai aksen melambangkan semangat dan keberanian masyarakat Betawi.', 'Hitam, Putih, Merah, Coklat Keemasan', 'Batik Tulis, Batik Cap', 'Motif yang relatif sederhana secara geometris namun memerlukan presisi tinggi dalam penerapan malam. Teknik cap sering digunakan untuk efisiensi produksi.', 'Kain serbet, taplak meja, selendang, dan busana adat Betawi. Sering digunakan sebagai border pada busana resmi kedaerahan.', 'Upacara Adat Betawi, Acara Resmi Daerah, Dekorasi', 'Terbatas pada daerah tertentu', 80000, 280000, 700000, 2500000, 'Shahab, A. (2001). Robinhood Betawi: Si Pitung. Jakarta: Republika; Museum Tekstil Jakarta (2018). Koleksi Batik Betawi.', '2026-07-15 21:04:36'),
(4, 'Batik Mega Mendung', 'JawaBarat_MegaMendung', 'Cirebon', 'Jawa', 'Jawa Barat', 'Mega Mendung adalah ikon batik Cirebon yang telah mendapat pengakuan UNESCO sebagai Warisan Budaya Tak Benda. Motif ini lahir dari akulturasi budaya Jawa dan pengaruh Tiongkok melalui pedagang dan seniman Tionghoa di Cirebon pada abad ke-15 hingga 17. Konon motif ini pertama kali dibuat oleh Sunan Gunung Jati.', 'Mega berarti awan, mendung berarti teduh. Motif ini melambangkan pembawa hujan sebagai kesuburan dan kemakmuran. Dalam tradisi Tionghoa, awan juga melambangkan transisi antara langit dan bumi — antara yang ilahi dan yang fana. Pemakainya diharapkan memiliki jiwa yang sejuk, sabar, dan membawa manfaat bagi sekitarnya.', 'Berbentuk awan berlapis-lapis (gradasi 3 hingga 7 warna) dengan tepi bergelombang khas. Goresan awan besar dan penuh dengan komposisi yang dinamis namun tetap seimbang. Tidak menggunakan motif isian kecil yang rumit.', 'Biru melambangkan langit dan ketenangan; merah melambangkan keberanian dan semangat; putih melambangkan kesucian. Gradasi warna dari gelap ke terang menggambarkan transisi dari kegelapan menuju cahaya.', 'Biru, Merah, Putih, Hitam', 'Batik Tulis, Batik Cap', 'Proses pewarnaan dilakukan secara bertahap untuk menciptakan efek gradasi yang khas. Setiap lapisan warna memerlukan proses tutup-celup yang teliti. Batik tulis Mega Mendung menggunakan canting halus untuk detail goresan awan.', 'Pakaian sehari-hari, busana resmi, fashion modern. Popularitas internasional menjadikannya pilihan utama promosi budaya Indonesia di luar negeri.', 'Casual, Fashion, Formal, Wisuda, Festival Budaya', 'Umum digunakan', 200000, 800000, 2000000, 8000000, 'Tirta, I. (2009). Batik: A Play of Lights and Shadows. Jakarta: PT Gaya Favorit Press; UNESCO (2009). Indonesian Batik — Intangible Cultural Heritage.', '2026-07-15 21:04:36'),
(5, 'Batik Jlamprang', 'JawaTengah_Jlamprang', 'Pekalongan', 'Jawa', 'Jawa Tengah', 'Jlamprang adalah motif batik tradisional Pekalongan yang mendapat pengaruh dari motif patola India — kain sutra mewah dari Gujarat yang dibawa pedagang ke pantai utara Jawa. Seniman batik Pekalongan mengadaptasikan pola geometris patola ke dalam teknik batik sejak abad ke-18.', 'Jlamprang melambangkan kemakmuran, keberkahan, dan keteraturan hidup. Pola simetrisnya mencerminkan keseimbangan dan harmoni dalam kehidupan, sesuai filosofi masyarakat pesisir Pekalongan yang terbuka terhadap pengaruh budaya luar namun tetap mempertahankan identitas lokal.', 'Berbentuk pola geometris simetris yang sangat presisi, menyerupai bintang atau roset dengan banyak sisi yang berulang secara konsisten. Setiap unit motif terdiri dari bentuk-bentuk diamond dan segitiga yang tersusun dengan matematika tinggi.', 'Merah melambangkan semangat dan keberanian; biru melambangkan ketenangan; hitam melambangkan keteguhan; putih melambangkan kesucian. Kombinasi warna mencerminkan semangat kosmopolit Pekalongan.', 'Merah, Biru, Hitam, Putih', 'Batik Tulis, Batik Cap', 'Teknik pembuatan memerlukan presisi geometris yang tinggi. Penggunaan alat bantu seperti mistar sering diperlukan. Motif yang berulang secara konsisten menjadikan batik cap lebih efisien untuk produksi massal.', 'Pakaian sehari-hari, busana resmi ringan, fashion modern. Motif yang tegas dan bersih cocok untuk berbagai kesempatan.', 'Casual, Formal, Fashion, Wisuda', 'Umum digunakan', 100000, 400000, 1000000, 4000000, 'Doellah, H.S. (2002). Batik: The Impact of Time and Environment. Surakarta: Danar Hadi; Tirta, I. (2009). Batik: A Play of Lights and Shadows.', '2026-07-15 21:04:36'),
(6, 'Batik Truntum', 'JawaTengah_Truntum', 'Surakarta', 'Jawa', 'Jawa Tengah', 'Motif Truntum diciptakan oleh Kanjeng Ratu Kencana, permaisuri Pakubuwono III, pada abad ke-18. Dikisahkan beliau menciptakan motif ini di tengah kesepian saat sang raja berpoligami, sebagai ekspresi kerinduan dan pengabdian cinta yang tak padam.', 'Truntum berasal dari kata \"taruntum\" yang berarti tumbuh kembali atau bersemi kembali. Motif ini melambangkan cinta yang terus bertumbuh dan tidak pernah padam meski terluka. Dalam tradisi pernikahan Jawa, Truntum dikenakan orang tua pengantin sebagai doa agar cinta anak mereka abadi dan terus bersemi.', 'Berupa bintang-bintang kecil menyerupai bunga Truntum dengan delapan kelopak yang tersebar merata di seluruh permukaan kain berlatar hitam. Kepadatan motif yang merata menciptakan efek galaksi bintang yang indah dan khidmat.', 'Hitam melambangkan kedalaman dan keteguhan cinta; emas/krem melambangkan kemuliaan dan nilai yang tak ternilai dari cinta sejati; putih melambangkan kesucian niat.', 'Hitam, Emas, Krem, Putih', 'Batik Tulis', 'Dibuat dengan teknik batik tulis menggunakan canting halus. Latar hitam dihasilkan dari proses pencelupan berulang dengan pewarna soga atau wenter hitam. Detail bintang kecil memerlukan keahlian tinggi dari pembatik.', 'Khusus digunakan oleh orang tua pengantin dalam upacara pernikahan adat Jawa sebagai simbol doa dan restu. Kini juga digunakan dalam konteks formal dan koleksi.', 'Pernikahan Adat Jawa (Orang Tua Pengantin), Upacara Adat, Acara Resmi', 'Digunakan pada upacara adat tertentu', 150000, 500000, 1500000, 5000000, 'Doellah, H.S. (2002). Batik: The Impact of Time and Environment. Surakarta: Danar Hadi; Gustami, S.P. (2007). Butir-Butir Mutiara Estetika Timur. Yogyakarta: Prasista.', '2026-07-15 21:04:36'),
(7, 'Batik Gentongan', 'JawaTimur_Gentongan', 'Madura', 'Jawa', 'Jawa Timur', 'Batik Gentongan adalah batik tradisional dari Tanjungbumi, Bangkalan, Madura. Nama \"Gentongan\" berasal dari \"gentong\" — tempayan besar yang digunakan sebagai wadah pencelupan kain dalam proses pewarnaan tradisional yang memerlukan waktu sangat lama.', 'Gentongan melambangkan kesabaran, ketekunan, dan hasil kerja keras yang bernilai tinggi. Proses pembuatannya yang panjang — bisa memakan waktu berbulan-bulan hingga bertahun-tahun — mencerminkan filosofi Madura bahwa sesuatu yang bernilai membutuhkan pengorbanan dan kesabaran.', 'Motif dengan corak alami dan warna yang kaya hasil fermentasi lama dalam gentong tanah liat. Ciri khas: warna merah mangrove yang kuat, motif flora abstrak, dan tekstur kain yang khas akibat proses pencelupan berulang.', 'Merah tua dari tanaman mangrove melambangkan keteguhan dan semangat Madura; hitam melambangkan kedalaman dan kewibawaan; coklat melambangkan alam dan bumi tempat berpijak.', 'Merah Tua, Hitam, Coklat, Biru Tua', 'Batik Tulis', 'Proses sangat unik: kain dicelup dalam gentong tanah liat berisi campuran pewarna alam (mangrove, indigo, tingi) yang difermentasi selama berbulan-bulan. Setiap tahap pencelupan diselingi penjemuran dan pelorodan malam.', 'Kain berkualitas tinggi untuk upacara adat Madura, hadiah prestisius, koleksi seni tekstil.', 'Upacara Adat Madura, Koleksi Seni, Hadiah Prestisius', 'Digunakan pada acara khusus', 300000, 1200000, 3000000, 12000000, 'Kerlogue, F. (2004). Batik: Design, Style & History. London: Thames & Hudson; Pusat Penelitian Batik Balai Besar Kerajinan dan Batik Yogyakarta (2020).', '2026-07-15 21:04:36'),
(8, 'Batik Pring', 'JawaTimur_Pring', 'Banyuwangi', 'Jawa', 'Jawa Timur', 'Batik Gajah Oling atau Pring (bambu) adalah motif batik khas Banyuwangi yang telah ada sejak zaman Kerajaan Blambangan. Motif ini merupakan ekspresi identitas suku Osing — penduduk asli Banyuwangi yang memiliki bahasa dan tradisi tersendiri.', 'Pring (bambu) melambangkan keteguhan, kelenturan, dan kemampuan beradaptasi. Bambu meski lentur tidak akan patah oleh angin kencang — filosofi ini mencerminkan karakter masyarakat Osing Banyuwangi yang kuat menghadapi berbagai tantangan sejarah.', 'Motif utama berupa stilisasi batang dan daun bambu (pring) yang digambar secara ekspresif dengan goresan kuat. Kadang dipadukan dengan motif ular naga atau burung sebagai pelengkap.', 'Hijau melambangkan alam dan kesuburan bambu; coklat melambangkan tanah tempat bambu tumbuh; putih melambangkan kesucian; hitam melambangkan keteguhan.', 'Hijau, Coklat, Putih, Hitam', 'Batik Tulis, Batik Cap', 'Menggunakan teknik batik tulis dengan goresan bebas dan ekspresif. Pewarnaan menggunakan perpaduan pewarna alam dan sintetis. Karakteristik goresan bebas mencerminkan semangat seni Osing.', 'Busana casual khas Banyuwangi, festival budaya Osing, souvenir daerah, busana sehari-hari.', 'Festival Budaya Osing, Casual, Fashion, Souvenir', 'Terbatas pada daerah tertentu', 100000, 380000, 1000000, 3800000, 'Pemda Kabupaten Banyuwangi (2017). Batik Using: Warisan Budaya Suku Osing; Dinas Kebudayaan Banyuwangi.', '2026-07-15 21:04:36'),
(9, 'Batik Kawung', 'Yogyakarta_Kawung', 'Yogyakarta', 'Jawa', 'DI Yogyakarta', 'Kawung merupakan salah satu motif batik paling kuno di Jawa, diyakini sudah ada sejak abad ke-13 berdasarkan relief di Candi Prambanan. Motif ini dahulu eksklusif digunakan oleh keluarga kerajaan Mataram dan beberapa kalangan tertentu yang mendapat izin khusus.', 'Motif Kawung terinspirasi dari buah aren (kawung) atau kapuk yang dibelah empat. Melambangkan empat arah mata angin dan kesempurnaan hidup. Secara filosofis, kawung mengajarkan keseimbangan, kemurnian hati, dan pengendalian diri — nilai-nilai utama dalam tradisi spiritual Jawa.', 'Terdiri dari lingkaran elips atau oval yang saling bersinggungan membentuk pola empat kelopak bunga. Setiap unit terdiri dari empat oval yang melingkupi sebuah titik pusat. Pola berulang secara konsisten membentuk komposisi geometris yang elegan.', 'Putih melambangkan kesucian dan kemurnian hati; hitam melambangkan keteguhan dan kedalaman batin; coklat melambangkan kebijaksanaan yang matang.', 'Putih, Hitam, Coklat Muda, Krem', 'Batik Tulis', 'Batik tulis keraton dengan presisi geometris tinggi. Menggunakan pewarna tradisional soga (coklat) dan wedel (biru-hitam). Setiap unit oval harus simetris sempurna.', 'Upacara keraton Yogyakarta, pernikahan adat Jawa, wisuda, acara budaya resmi.', 'Upacara Adat Jawa, Pernikahan, Wisuda, Acara Resmi', 'Digunakan pada lingkungan keraton', 100000, 400000, 1200000, 4000000, 'Doellah, H.S. (2002). Batik: The Impact of Time and Environment. Surakarta: Danar Hadi; Keraton Ngayogyakarta Hadiningrat (2016). Batik Keraton Yogyakarta.', '2026-07-15 21:04:36'),
(10, 'Batik Parang Rusak', 'Yogyakarta_ParangRusak', 'Yogyakarta', 'Jawa', 'DI Yogyakarta', 'Parang Rusak adalah motif batik tertua dan paling sakral di Yogyakarta, dikaitkan dengan penciptaan oleh Sultan Agung Hanyokrokusumo pada abad ke-17. Secara historis, motif ini hanya boleh dikenakan oleh Sultan dan keluarga terdekatnya.', 'Parang berasal dari kata \"pereng\" (lereng) dan Rusak menggambarkan semangat yang tidak pernah berhenti. Seperti ombak laut yang terus bergerak tanpa henti, motif ini melambangkan semangat juang, keteguhan hati, dan kekuatan yang berkelanjutan dalam menghadapi cobaan.', 'Berbentuk diagonal menyerupai huruf S yang saling terhubung dalam deretan berulang dari kiri atas ke kanan bawah. Garis-garis kuat dan tegas menciptakan komposisi yang dinamis dan bertenaga.', 'Coklat sogan melambangkan kematangan dan kebijaksanaan pemimpin; hitam melambangkan keteguhan dan keberanian; krem melambangkan kejernihan pikiran.', 'Coklat Sogan, Hitam, Krem, Putih', 'Batik Tulis', 'Batik tulis dengan tingkat kesulitan sangat tinggi. Garis diagonal yang konsisten dan simetris memerlukan keahlian pembatik tingkat master. Pewarnaan soga tradisional dari tumbuhan soga tingi.', 'Upacara keraton, pernikahan adat Jawa tingkat tinggi, acara resmi kenegaraan.', 'Upacara Keraton, Pernikahan Adat Jawa, Acara Kenegaraan', 'Digunakan pada lingkungan keraton', 150000, 600000, 2000000, 7000000, 'Doellah, H.S. (2002). Batik: The Impact of Time and Environment. Surakarta: Danar Hadi; Keraton Ngayogyakarta Hadiningrat (2016). Batik Keraton Yogyakarta.', '2026-07-15 21:04:36'),
(11, 'Batik Dayak', 'Kalimantan_Dayak', 'Kalimantan', 'Kalimantan', 'Kalimantan Tengah', 'Batik Dayak merupakan interpretasi modern dari seni ukir, tenunan, dan tattoo tradisional suku Dayak Kalimantan ke dalam medium batik. Meski teknik membatik bukan asli Dayak, motif-motif tradisional mereka diadaptasi secara kreatif ke dalam teknik batik sejak pertengahan abad ke-20.', 'Motif Dayak mengandung makna spiritual yang sangat dalam — setiap simbol terhubung dengan alam, roh leluhur, dan keseimbangan kosmis. Burung Enggang sebagai totem suci melambangkan kebebasan dan kemuliaan; motif sulur melambangkan siklus kehidupan yang tak terputus.', 'Didominasi motif Burung Enggang (hornbill) yang sakral, sulur tanaman merambat Kalimantan, dan pola geometris khas Dayak. Komposisi asimetris yang dinamis dengan detail yang sangat kaya.', 'Merah melambangkan semangat dan keberanian suku Dayak; hitam melambangkan kekuatan dan perlindungan roh leluhur; emas/kuning melambangkan kemuliaan dan kejayaan; coklat melambangkan tanah Kalimantan.', 'Merah, Hitam, Emas, Coklat, Oranye', 'Batik Tulis, Batik Cap', 'Menggunakan teknik batik tulis dengan adaptasi motif dari seni ukir dan tato tradisional Dayak. Pewarnaan menggunakan pewarna alam Kalimantan seperti akar mengkudu dan kunyit hutan.', 'Festival budaya Dayak, fashion etnik Nusantara, promosi pariwisata Kalimantan, busana adat modern.', 'Festival Budaya Dayak, Fashion Etnik, Casual, Promosi Budaya', 'Umum digunakan', 100000, 400000, 1000000, 4000000, 'Sellato, B. (1989). Hornbill and Dragon: Kalimantan, Sarawak, Sabah, Brunei. Jakarta: Elf Aquitaine Indonesie; Dinas Kebudayaan Kalimantan Tengah (2018).', '2026-07-15 21:04:36'),
(12, 'Batik Insang', 'KalimantanBarat_Insang', 'Pontianak', 'Kalimantan', 'Kalimantan Barat', 'Batik Insang adalah batik khas Pontianak, Kalimantan Barat, yang terinspirasi dari insang ikan — motif yang menggambarkan kehidupan masyarakat Dayak dan Melayu yang sangat bergantung pada sungai dan laut.', 'Insang ikan melambangkan kebersamaan, saling ketergantungan, dan sistem kehidupan yang saling mendukung. Seperti insang yang memungkinkan ikan bernapas di dalam air, motif ini mencerminkan kemampuan adaptasi dan harmoni manusia dengan alam.', 'Berbentuk pola menyerupai susunan sisik atau insang ikan yang berulang secara teratur. Pola dapat berbentuk setengah lingkaran bertumpuk atau oval memanjang yang tersusun seperti genteng. Sangat geometris dan teratur.', 'Biru melambangkan air sungai Kapuas yang menjadi sumber kehidupan Pontianak; emas melambangkan kemakmuran dan kekayaan alam Kalimantan Barat; merah melambangkan semangat dan keberanian.', 'Biru, Emas, Merah, Putih', 'Batik Tulis, Batik Cap', 'Teknik batik dengan pola geometris berulang yang memerlukan ketelitian. Tersedia dalam berbagai kualitas mulai dari cap sederhana hingga tulis premium.', 'Busana resmi khas Kalimantan Barat, souvenir Pontianak, festival budaya, fashion.', 'Acara Resmi Daerah, Festival Budaya, Casual, Souvenir', 'Terbatas pada daerah tertentu', 90000, 360000, 900000, 3600000, 'Dinas Kebudayaan dan Pariwisata Kalimantan Barat (2019). Batik Insang Pontianak; Pemda Kalimantan Barat (2020).', '2026-07-15 21:04:36'),
(13, 'Batik Rumah Minang', 'SumateraBarat_RumahMinang', 'Padang', 'Sumatera', 'Sumatera Barat', 'Batik RumahMinang merupakan adaptasi motif arsitektur rumah gadang (rumah adat Minangkabau) ke dalam medium batik. Berkembang sebagai upaya pelestarian dan modernisasi budaya Minangkabau pada era modern.', 'Rumah Gadang melambangkan sistem matrilineal Minangkabau, solidaritas keluarga besar (kaum), dan kekuatan budaya yang telah bertahan ribuan tahun. Atap yang melengkung ke atas seperti tanduk kerbau melambangkan kemenangan (manang) yang menjadi asal-usul nama Minangkabau.', 'Menampilkan stilisasi Rumah Gadang dengan atap gonjong melengkung khas yang menjadi motif utama. Sering dipadukan dengan motif songket Minang, ukiran pucuk rebung, dan ornamen flora khas Sumatera Barat.', 'Merah melambangkan keberanian dan semangat; hitam melambangkan keteguhan adat; emas melambangkan kemuliaan tradisi Minangkabau; hijau melambangkan alam dan pertanian.', 'Merah, Hitam, Emas, Hijau', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan teknik batik modern dengan inspirasi motif dari ukiran kayu dan tenunan songket Minangkabau. Desain sering berkolaborasi dengan seniman Minang untuk menjaga otentisitas.', 'Busana casual dan semi-formal, souvenir khas Sumatera Barat, fashion modern bertema budaya Minang.', 'Casual, Fashion, Souvenir, Acara Budaya Minang', 'Umum digunakan', 85000, 320000, 850000, 3200000, 'Navis, A.A. (1984). Alam Terkembang Jadi Guru: Adat dan Kebudayaan Minangkabau. Jakarta: PT Pustaka Grafitipers; Dinas Kebudayaan Sumatera Barat.', '2026-07-15 21:04:36'),
(14, 'Batik Boraspati', 'SumateraUtara_Boraspati', 'Medan', 'Sumatera', 'Sumatera Utara', 'Boraspati adalah batik khas Batak yang mengambil inspirasinya dari cicak (boraspati ni tano dalam bahasa Batak Toba) — hewan yang dianggap sebagai penunggu rumah dan pembawa keberuntungan dalam kepercayaan Batak.', 'Boraspati ni Tano (cicak pelindung tanah) dalam kepercayaan Batak melambangkan penjaga rumah, pelindung keluarga, dan pembawa rezeki. Motif ini mencerminkan sistem kepercayaan animisme Batak yang kaya dan penghormatan terhadap makhluk hidup sekitar.', 'Menampilkan stilisasi cicak dalam berbagai komposisi yang dipadukan dengan ornamen tradisional Batak seperti gorga (ukiran Batak), ulos, dan motif geometris khas. Warna-warna kuat dan kontras menjadi ciri khas.', 'Merah melambangkan semangat dan keberanian Batak; hitam melambangkan perlindungan dan keteguhan; putih melambangkan kesucian dan kejujuran.', 'Merah, Hitam, Putih, Coklat Kemerahan', 'Batik Tulis, Batik Cap', 'Menggunakan teknik batik dengan motif terinspirasi dari ukiran gorga tradisional Batak. Perpaduan teknik batik dengan estetika Batak menciptakan produk yang unik.', 'Festival budaya Batak, busana resmi khas Sumatera Utara, souvenir Medan, promosi budaya.', 'Festival Budaya Batak, Casual, Fashion, Souvenir', 'Terbatas pada daerah tertentu', 90000, 350000, 900000, 3500000, 'Vergouwen, J.C. (1964). The Social Organisation and Customary Law of the Toba-Batak. Dordrecht: Springer; Dinas Kebudayaan Sumatera Utara (2019).', '2026-07-15 21:04:36'),
(15, 'Batik Pintu Aceh', 'SumateraUtara_PintuAceh', 'Banda Aceh', 'Sumatera', 'Aceh', 'Batik Pintu Aceh terinspirasi dari ornamen ukiran pintu rumah adat Aceh yang kaya dengan motif geometris dan arabesk Islami. Motif ini mencerminkan pengaruh Islam yang sangat kuat dalam seni dan budaya Aceh.', 'Ornamen pintu dalam arsitektur Aceh bukan sekadar elemen dekoratif, tetapi merupakan simbolisasi dari batas antara dunia luar dan dalam, antara yang profan dan yang sakral. Motif ini melambangkan keagungan Islam, keteraturan hidup yang berpedoman pada nilai-nilai Islami.', 'Pola geometris berbentuk kisi-kisi ukiran khas Aceh yang terinspirasi dari motif arabesk dan kaligrafi Islam. Komposisi simetris yang sangat teratur mencerminkan keteraturan (order) dalam pandangan hidup Islami.', 'Hijau melambangkan Islam yang menjadi identitas utama Aceh; putih melambangkan kesucian; emas melambangkan kemuliaan dan kejayaan peradaban Islam di Aceh.', 'Hijau, Putih, Emas, Hitam', 'Batik Tulis, Batik Cap', 'Menggunakan teknik batik dengan motif yang diadaptasi dari ukiran kayu Aceh. Pola geometris yang presisi memerlukan ketelitian tinggi dalam proses pembatikan.', 'Busana Muslim, acara resmi keagamaan, souvenir khas Aceh, festival budaya.', 'Acara Keagamaan Islam, Acara Resmi, Souvenir, Festival Budaya', 'Terbatas pada daerah tertentu', 95000, 380000, 950000, 3800000, 'Lombard, D. (1967). Le Sultanat d\'Atjeh au temps d\'Iskandar Muda. Paris: EFEO; Dinas Kebudayaan dan Pariwisata Aceh (2018). Warisan Budaya Aceh.', '2026-07-15 21:04:36'),
(16, 'Batik Gajah', 'Lampung_Gajah', 'Lampung', 'Sumatera', 'Lampung', 'Batik Gajah Way Kambas adalah batik khas Lampung yang terinspirasi dari gajah Sumatera (Elephas maximus sumatranus) yang menjadi hewan ikonik Taman Nasional Way Kambas di Lampung. Motif ini berkembang sebagai upaya promosi konservasi dan identitas budaya Lampung.', 'Gajah dalam tradisi Lampung dan Melayu melambangkan kekuatan, kebijaksanaan, dan kesetiaan. Sebagai hewan yang dilindungi, motif ini juga mengandung pesan konservasi — pentingnya menjaga keseimbangan alam dan melindungi satwa liar Sumatera.', 'Menampilkan stilisasi gajah Sumatera dalam berbagai pose yang dipadukan dengan motif flora khas hutan Lampung seperti bunga tanjung dan daun pisang. Komposisi dinamis dan ekspresif.', 'Coklat dan abu-abu mewakili warna kulit gajah; hijau mewakili hutan hujan Lampung; hitam melambangkan kekuatan; putih melambangkan kesucian niat konservasi.', 'Coklat, Abu-abu, Hijau, Hitam, Putih', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan berbagai teknik tergantung segmen pasar. Motif gajah sering digambar secara ekspresif dengan goresan bebas untuk menghasilkan karakter yang kuat.', 'Busana casual dan semi-formal, souvenir khas Lampung, promosi pariwisata Way Kambas, fashion bertema konservasi.', 'Casual, Fashion, Souvenir, Promosi Konservasi', 'Umum digunakan', 80000, 300000, 800000, 3000000, 'Dinas Kebudayaan dan Pariwisata Lampung (2020). Batik Lampung: Ekspresi Budaya Siger; TNWK (2019). Gajah Sumatera.', '2026-07-15 21:04:36'),
(17, 'Batik Bledheg', 'Lampung_Bledheg', 'Lampung', 'Sumatera', 'Lampung', 'Batik Bledheg terinspirasi dari kata \"bledheg\" dalam bahasa Jawa (yang juga digunakan di komunitas Jawa-Lampung transmigran) yang berarti petir/kilat. Motif ini juga terinspirasi dari motif pucuk rebung yang umum dalam tenunan tradisional Lampung.', 'Bledheg (petir) melambangkan kekuatan alam yang dahsyat namun memberikan kehidupan — petir yang diikuti hujan membawa kesuburan bagi tanah. Filosofinya mengajarkan bahwa kekuatan yang besar hendaknya digunakan untuk kebaikan dan kesuburan bagi masyarakat.', 'Motif geometris berupa pola zigzag atau zig-zag yang kuat dan berirama menyerupai kilat petir. Dipadukan dengan motif pucuk rebung yang segitiga. Komposisi tegas dan bersih.', 'Merah melambangkan energi dan kekuatan; hitam melambangkan ketegasan; putih melambangkan harapan; emas melambangkan cahaya yang dihasilkan kilat.', 'Merah, Hitam, Putih, Emas', 'Batik Tulis, Batik Cap', 'Pola geometris yang tegas memudahkan produksi dengan teknik cap. Batik tulis tersedia untuk kualitas premium dengan detail yang lebih kaya.', 'Busana casual, souvenir khas Lampung, acara budaya daerah.', 'Casual, Fashion, Souvenir, Acara Budaya Daerah', 'Umum digunakan', 75000, 280000, 750000, 2800000, 'Dinas Kebudayaan dan Pariwisata Lampung (2020). Batik Lampung: Ekspresi Budaya Siger.', '2026-07-15 21:04:36'),
(18, 'Batik Lontara', 'SulawesiSelatan_Lontara', 'Makassar', 'Sulawesi', 'Sulawesi Selatan', 'Batik Lontara merupakan inovasi budaya yang mengintegrasikan aksara Lontara — sistem tulisan tradisional suku Bugis dan Makassar — ke dalam motif batik. Batik ini berkembang pesat sejak tahun 2000-an sebagai identitas tekstil Sulawesi Selatan.', 'Aksara Lontara melambangkan kekayaan intelektual peradaban Bugis-Makassar yang telah menghasilkan naskah-naskah bersejarah termasuk epos I La Galigo. Motif ini merayakan tradisi literasi dan kebijaksanaan leluhur Sulawesi Selatan yang tertuang dalam aksara kuno.', 'Menampilkan aksara Lontara Bugis-Makassar sebagai elemen dekoratif utama yang disusun dalam berbagai komposisi kreatif. Huruf-huruf Lontara yang unik dan indah menjadi ornamen yang secara estetis sangat kuat.', 'Merah melambangkan keberanian dan semangat phinisi; hitam melambangkan keteguhan dan kedalaman pengetahuan; emas/kuning melambangkan kemuliaan tradisi intelektual Bugis-Makassar.', 'Merah, Hitam, Emas, Putih', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan teknik batik modern dengan motif aksara Lontara. Aksara yang khas dan unik memberikan nilai estetis yang tinggi. Tersedia dalam berbagai kualitas dan harga.', 'Busana resmi khas Sulawesi Selatan, souvenir Makassar, promosi budaya Bugis-Makassar, fashion modern.', 'Acara Resmi Daerah, Fashion, Souvenir, Festival Budaya', 'Umum digunakan', 90000, 360000, 900000, 3600000, 'Pelras, C. (1996). The Bugis. Oxford: Blackwell Publishers; Dinas Kebudayaan Sulawesi Selatan (2019). Batik Lontara.', '2026-07-15 21:04:36'),
(19, 'Batik Asmat', 'Papua_Asmat', 'Agats', 'Papua', 'Papua Selatan', 'Batik Papua Asmat merupakan adaptasi seni ukir Suku Asmat — salah satu tradisi seni ukir paling terkenal di dunia — ke dalam medium batik. Suku Asmat di Papua Selatan dikenal dengan ukiran kayu yang mengandung makna spiritual mendalam.', 'Motif Asmat terinspirasi dari simbol-simbol spiritual suku Asmat yang berhubungan dengan leluhur, roh alam, dan siklus kehidupan-kematian. Setiap ukiran adalah \"doa\" yang ditujukan kepada roh leluhur untuk keselamatan dan kemakmuran suku.', 'Menampilkan stilisasi motif ukiran Asmat seperti sosok manusia stilistik (mbis), perahu, ikan, dan elemen alam Papua. Garis-garis yang kuat dan kontras menjadi ciri khas estetika Asmat.', 'Hitam dan putih melambangkan dualisme kehidupan dan kematian dalam kepercayaan Asmat; merah oker melambangkan tanah Papua dan darah leluhur yang mengalir dalam tradisi.', 'Hitam, Putih, Merah Oker, Coklat Tanah', 'Batik Tulis, Batik Cap', 'Menggunakan teknik batik dengan adaptasi motif dari seni ukir kayu Asmat. Proses kolaborasi dengan seniman Asmat penting untuk menjaga otentisitas makna spiritual.', 'Festival budaya Papua, promosi pariwisata, koleksi seni, fashion etnik Nusantara.', 'Festival Budaya Papua, Koleksi Seni, Fashion Etnik, Promosi Pariwisata', 'Terbatas pada daerah tertentu', 120000, 480000, 1200000, 4800000, 'Schneebaum, T. (1985). Embodied Spirits: Ritual Carvings of the Asmat. Salem: Peabody Museum; Dinas Kebudayaan Papua (2019).', '2026-07-15 21:04:36'),
(20, 'Batik Cendrawasih', 'Papua_Cendrawasih', 'Jayapura', 'Papua', 'Papua', 'Batik Cenderawasih mengambil inspirasi dari Burung Cenderawasih (bird of paradise) — burung endemik Papua yang dianggap sebagai burung surga dan menjadi kebanggaan identitas Papua. Batik ini telah menjadi identitas tekstil Papua yang paling dikenal secara nasional.', 'Cenderawasih dalam kepercayaan Papua adalah burung yang berasal dari surga, pembawa keberuntungan, dan simbol keindahan alam Papua yang tak tertandingi. Motif ini mengajak setiap pemakainya untuk menghargai dan melestarikan keindahan alam Papua.', 'Menampilkan Burung Cenderawasih dalam berbagai pose dengan bulu-bulu indahnya yang khas, dikelilingi flora tropis Papua seperti anggrek, pakis raksasa, dan ornamen geometris suku-suku Papua.', 'Emas dan kuning melambangkan keindahan bulu Cenderawasih dan kejayaan; merah melambangkan semangat; biru melambangkan langit Papua; hijau melambangkan hutan Papua yang rimbun.', 'Emas, Kuning, Merah, Biru, Hijau, Hitam', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan teknik batik yang memadukan detail halus untuk bulu Cenderawasih dengan motif flora yang kaya. Tersedia dalam berbagai kualitas untuk berbagai segmen pasar.', 'Busana resmi Papua, souvenir terpopuler dari Papua, fashion modern bertema alam, promosi pariwisata Papua.', 'Acara Resmi Papua, Fashion, Souvenir, Festival Budaya, Casual', 'Umum digunakan', 100000, 400000, 1000000, 4000000, 'Beehler, B.M., Pratt, T.K., & Zimmerman, D.A. (1986). Birds of New Guinea. Princeton: Princeton University Press; Dinas Kebudayaan Papua (2019).', '2026-07-15 21:04:36'),
(21, 'Batik Pala', 'Maluku_Pala', 'Ambon', 'Maluku', 'Maluku', 'Batik Pala terinspirasi dari tanaman pala (Myristica fragrans) — rempah yang menjadikan Maluku terkenal sebagai \"Spice Islands\" dan menjadi rebutan bangsa-bangsa Eropa selama ratusan tahun. Pala adalah simbol kekayaan, kejayaan, dan identitas Maluku.', 'Pala melambangkan kekayaan alam Maluku yang menjadi daya tarik dunia dan mengubah sejarah perdagangan global. Filosofinya mengingatkan betapa berharganya kekayaan alam yang harus dijaga dan dikelola dengan bijaksana. Pala juga melambangkan keharuman nama Maluku di pentas sejarah dunia.', 'Menampilkan stilisasi buah pala, bunga pala, dan daun pala dalam berbagai komposisi yang kaya dan berirama. Sering dikombinasikan dengan motif ikan dan laut yang mencerminkan kehidupan kepulauan Maluku.', 'Merah melambangkan fuli (selaput pala) yang berwarna merah cerah dan berharga; hijau melambangkan daun dan buah pala yang segar; coklat melambangkan biji pala yang bernilai tinggi.', 'Merah, Hijau, Coklat, Krem, Oranye', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan teknik batik modern dengan motif yang menggabungkan detail botanikal pala dengan ornamen Maluku. Warna-warna cerah mencerminkan keceriaan masyarakat kepulauan.', 'Busana casual dan semi-formal, souvenir khas Maluku, festival budaya, promosi pariwisata.', 'Casual, Fashion, Souvenir, Festival Budaya, Acara Resmi Daerah', 'Umum digunakan', 85000, 330000, 850000, 3300000, 'Villiers, J. (1981). Trade and Society in the Banda Islands in the Sixteenth Century. Modern Asian Studies, 15(4); Dinas Kebudayaan Maluku (2019).', '2026-07-15 21:04:36'),
(22, 'Batik Lumbung', 'NTB_Lumbung', 'Mataram', 'Nusa Tenggara', 'Nusa Tenggara Barat', 'Batik Lumbung terinspirasi dari lumbung padi — bangunan penyimpan padi tradisional yang menjadi simbol kemakmuran dan ketahanan pangan masyarakat Lombok, Nusa Tenggara Barat. Lumbung juga merupakan ikon yang terpampang dalam lambang daerah NTB.', 'Lumbung melambangkan kemakmuran, ketahanan pangan, dan sistem gotong royong masyarakat Lombok yang telah berlangsung turun-temurun. Filosofinya mengajarkan pentingnya menyimpan hasil kerja keras untuk masa depan dan berbagi dengan sesama yang membutuhkan.', 'Menampilkan stilisasi arsitektur lumbung tradisional Lombok dengan atap jerami yang khas, dipadukan dengan motif padi, bunga kemangi, dan ornamen tradisional Sasak (suku asli Lombok).', 'Kuning/emas melambangkan padi yang menguning dan kemakmuran yang melimpah; coklat melambangkan tanah Lombok dan bangunan lumbung; hijau melambangkan kesuburan sawah Lombok.', 'Kuning Emas, Coklat, Hijau, Merah, Hitam', 'Batik Tulis, Batik Cap, Batik Printing', 'Menggunakan teknik batik dengan motif yang diadaptasi dari seni tenun Sasak dan arsitektur tradisional NTB. Pewarnaan menggunakan warna-warna cerah khas NTB.', 'Busana casual dan semi-formal, souvenir khas NTB/Lombok, festival budaya Sasak, promosi pariwisata.', 'Casual, Fashion, Souvenir, Festival Budaya, Acara Resmi Daerah', 'Umum digunakan', 80000, 300000, 800000, 3000000, 'Goris, R. (1960). The Position of the Blacksmiths. Leiden: KITLV; Dinas Kebudayaan dan Pariwisata NTB (2020). Batik Lumbung Lombok.', '2026-07-15 21:04:36');

