-- Table structure for table `prediksi`
--

CREATE TABLE `prediksi` (
  `id_prediksi` int(10) UNSIGNED NOT NULL,
  `id_user` int(10) UNSIGNED DEFAULT NULL,
  `nama_file` varchar(255) NOT NULL,
  `gambar_upload` longtext DEFAULT NULL,
  `hasil_prediksi` varchar(120) DEFAULT NULL,
  `confidence` float DEFAULT NULL,
  `id_motif` int(10) UNSIGNED DEFAULT NULL,
  `tanggal_prediksi` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

